import{c as a,Q as s,j as n,m as e}from"./chunks/framework.ga0D1uIo.js";const u=JSON.parse('{"title":"第二章：NLP 发展史","description":"","frontmatter":{},"headers":[],"relativePath":"nlp-introduction/history.md","filePath":"nlp-introduction/history.md","lastUpdated":1779795405000}'),o={name:"nlp-introduction/history.md"};function r(i,t,l,d,p,h){return s(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="第二章-nlp-发展史" tabindex="-1">第二章：NLP 发展史 <a class="header-anchor" href="#第二章-nlp-发展史" aria-label="Permalink to &quot;第二章：NLP 发展史&quot;">​</a></h1><p>NLP 的发展经历了多个阶段，从最初的手工规则到如今的大语言模型。理解这段历史，有助于我们把握技术演进的脉络，理解每项技术诞生的背景和动机。</p><hr><h2 id="第一阶段-规则系统时代-1950s-1980s" tabindex="-1">第一阶段：规则系统时代（1950s-1980s） <a class="header-anchor" href="#第一阶段-规则系统时代-1950s-1980s" aria-label="Permalink to &quot;第一阶段：规则系统时代（1950s-1980s）&quot;">​</a></h2><h3 id="时代背景" tabindex="-1">时代背景 <a class="header-anchor" href="#时代背景" aria-label="Permalink to &quot;时代背景&quot;">​</a></h3><p>在 20 世纪 50 年代至 80 年代初，自然语言处理主要依赖<strong>人工编写的语言规则</strong>。这些规则由语言学家和程序员手动制定，基于语法规则和词典来处理语言。</p><h3 id="代表系统" tabindex="-1">代表系统 <a class="header-anchor" href="#代表系统" aria-label="Permalink to &quot;代表系统&quot;">​</a></h3><h4 id="georgetown-ibm-实验-1954" tabindex="-1">Georgetown-IBM 实验（1954） <a class="header-anchor" href="#georgetown-ibm-实验-1954" aria-label="Permalink to &quot;Georgetown-IBM 实验（1954）&quot;">​</a></h4><p>这是人类历史上第一次公开演示的机器翻译系统。由乔治城大学和 IBM 联合开发，实验演示了将 60 多个俄语句子完全自动翻译成英语。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入（俄语）：Мы хотим видеть советскую Америку.</span></span>
<span class="line"><span>输出（英语）：We would like to see Soviet America.</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">局限性</p><p>该实验仅覆盖了 6 个语法规则和 250 个词汇条目，只能处理非常有限的句子结构。但它的意义在于证明了机器翻译的<strong>可能性</strong>。</p></div><h4 id="eliza-聊天机器人-1966" tabindex="-1">ELIZA 聊天机器人（1966） <a class="header-anchor" href="#eliza-聊天机器人-1966" aria-label="Permalink to &quot;ELIZA 聊天机器人（1966）&quot;">​</a></h4><p>ELIZA 由 MIT 的约瑟夫·魏岑鲍姆（Joseph Weizenbaum）开发，是世界上最早的聊天机器人之一。它模拟了一位心理治疗师，通过<strong>模式匹配</strong>和<strong>替换规则</strong>来生成回复。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：我感觉很不开心。</span></span>
<span class="line"><span>ELIZA：你为什么感觉不开心？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用户：因为我考试没考好。</span></span>
<span class="line"><span>ELIZA：考试没考好让你有什么感受？</span></span></code></pre></div><p>ELIZA 的工作原理非常简单：它使用一系列的<strong>模板规则</strong>，例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>规则：我感觉 &lt;X&gt;</span></span>
<span class="line"><span>回复：你为什么感觉 &lt;X&gt;？</span></span></code></pre></div><h3 id="优缺点" tabindex="-1">优缺点 <a class="header-anchor" href="#优缺点" aria-label="Permalink to &quot;优缺点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>精确可控</td><td>需要大量人工编写规则</td></tr><tr><td>可解释性强</td><td>无法处理歧义和新情况</td></tr><tr><td>在特定领域表现良好</td><td>扩展性差，维护成本高</td></tr></tbody></table><hr><h2 id="第二阶段-统计方法时代-1990s" tabindex="-1">第二阶段：统计方法时代（1990s） <a class="header-anchor" href="#第二阶段-统计方法时代-1990s" aria-label="Permalink to &quot;第二阶段：统计方法时代（1990s）&quot;">​</a></h2><h3 id="时代背景-1" tabindex="-1">时代背景 <a class="header-anchor" href="#时代背景-1" aria-label="Permalink to &quot;时代背景&quot;">​</a></h3><p>90 年代，随着计算能力的提升和大规模语料库的出现，<strong>统计方法</strong>逐渐取代规则系统成为主流。核心思想是：不再人工编写规则，而是让机器从大量文本数据中<strong>自动学习</strong>语言的模式和规律。</p><h3 id="核心方法" tabindex="-1">核心方法 <a class="header-anchor" href="#核心方法" aria-label="Permalink to &quot;核心方法&quot;">​</a></h3><h4 id="n-gram-模型" tabindex="-1">N-gram 模型 <a class="header-anchor" href="#n-gram-模型" aria-label="Permalink to &quot;N-gram 模型&quot;">​</a></h4><p>N-gram 是最早出现的统计语言模型之一。它的核心思想是：<strong>一个词出现的概率只取决于它前面的 N-1 个词</strong>。</p><p><strong>Bigram（2-gram）示例</strong>：</p><p>假设我们要计算句子&quot;今天 天气 很好&quot;的概率：</p><p>$$P(\\text{今天 天气 很好}) = P(\\text{今天}) \\times P(\\text{天气}|\\text{今天}) \\times P(\\text{很好}|\\text{天气})$$</p><p><strong>Trigram（3-gram）示例</strong>：</p><p>$$P(\\text{今天 天气 很好}) = P(\\text{今天}) \\times P(\\text{天气}|\\text{今天}) \\times P(\\text{很好}|\\text{今天 天气})$$</p><p>其中：</p><ul><li>$P(\\text{天气}|\\text{今天})$ 表示在&quot;今天&quot;出现的条件下，下一个词是&quot;天气&quot;的概率</li><li>这些概率通过统计语料库中词语出现的频率来估计</li></ul><p><strong>N-gram 的局限</strong>：</p><table tabindex="0"><thead><tr><th>问题</th><th>说明</th></tr></thead><tbody><tr><td>数据稀疏</td><td>当 N 增大时，很多 N-gram 组合在语料中从未出现</td></tr><tr><td>无法捕捉长距离依赖</td><td>只能看前 N-1 个词，无法理解长距离的语义关系</td></tr><tr><td>存储开销大</td><td>需要存储所有可能的 N-gram 及其频率</td></tr></tbody></table><h4 id="隐马尔可夫模型-hmm" tabindex="-1">隐马尔可夫模型（HMM） <a class="header-anchor" href="#隐马尔可夫模型-hmm" aria-label="Permalink to &quot;隐马尔可夫模型（HMM）&quot;">​</a></h4><p>HMM 是一种概率图模型，广泛应用于<strong>词性标注</strong>和<strong>语音识别</strong>。它假设：</p><ol><li>当前状态只依赖于前一个状态（马尔可夫假设）</li><li>当前的观测只依赖于当前的状态（输出独立性假设）</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>隐藏状态序列：名词 → 动词 → 形容词 → 名词</span></span>
<span class="line"><span>观测序列：    我   → 爱   → 美丽   → 花朵</span></span></code></pre></div><h3 id="优缺点-1" tabindex="-1">优缺点 <a class="header-anchor" href="#优缺点-1" aria-label="Permalink to &quot;优缺点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>从数据中自动学习</td><td>需要大量标注数据</td></tr><tr><td>能处理一定程度的歧义</td><td>特征工程复杂</td></tr><tr><td>有坚实的数学基础</td><td>难以捕捉复杂的语言现象</td></tr></tbody></table><hr><h2 id="第三阶段-机器学习时代-2000s" tabindex="-1">第三阶段：机器学习时代（2000s） <a class="header-anchor" href="#第三阶段-机器学习时代-2000s" aria-label="Permalink to &quot;第三阶段：机器学习时代（2000s）&quot;">​</a></h2><h3 id="时代背景-2" tabindex="-1">时代背景 <a class="header-anchor" href="#时代背景-2" aria-label="Permalink to &quot;时代背景&quot;">​</a></h3><p>进入 21 世纪，NLP 技术逐步引入传统机器学习方法。这一阶段的<strong>特征工程</strong>成为关键环节——研究者需要设计大量手工特征来提升模型性能。</p><h3 id="核心方法-1" tabindex="-1">核心方法 <a class="header-anchor" href="#核心方法-1" aria-label="Permalink to &quot;核心方法&quot;">​</a></h3><h4 id="逻辑回归-logistic-regression" tabindex="-1">逻辑回归（Logistic Regression） <a class="header-anchor" href="#逻辑回归-logistic-regression" aria-label="Permalink to &quot;逻辑回归（Logistic Regression）&quot;">​</a></h4><p>逻辑回归是最基础的分类模型之一，广泛应用于文本分类任务。</p><p>给定输入特征向量 $\\mathbf{x}$，逻辑回归的预测公式为：</p><p>$$P(y=1|\\mathbf{x}) = \\sigma(\\mathbf{w}^T\\mathbf{x} + b) = \\frac{1}{1 + e^{-(\\mathbf{w}^T\\mathbf{x} + b)}}$$</p><p>其中：</p><ul><li>$\\mathbf{x}$ 是输入的特征向量（如词频向量）</li><li>$\\mathbf{w}$ 是模型的权重向量</li><li>$b$ 是偏置项</li><li>$\\sigma$ 是 Sigmoid 函数，将输出映射到 [0, 1] 区间</li></ul><h4 id="支持向量机-svm" tabindex="-1">支持向量机（SVM） <a class="header-anchor" href="#支持向量机-svm" aria-label="Permalink to &quot;支持向量机（SVM）&quot;">​</a></h4><p>SVM 的核心思想是找到一个<strong>最优超平面</strong>，使得不同类别的样本之间的<strong>间隔最大化</strong>。</p><p>$$\\min_{\\mathbf{w}, b} \\frac{1}{2} |\\mathbf{w}|^2 \\quad \\text{s.t.} \\quad y_i(\\mathbf{w}^T\\mathbf{x}_i + b) \\geq 1, \\forall i$$</p><p>其中：</p><ul><li>$\\mathbf{w}$ 是超平面的法向量</li><li>$b$ 是偏置</li><li>$y_i$ 是第 $i$ 个样本的标签（+1 或 -1）</li><li>$|\\mathbf{w}|^2$ 是权重的 L2 范数，用于控制模型复杂度</li></ul><h4 id="条件随机场-crf" tabindex="-1">条件随机场（CRF） <a class="header-anchor" href="#条件随机场-crf" aria-label="Permalink to &quot;条件随机场（CRF）&quot;">​</a></h4><p>CRF 是一种判别式概率图模型，特别适合<strong>序列标注</strong>任务（如命名实体识别、词性标注）。</p><p>CRF 定义了给定观测序列 $\\mathbf{x}$ 时，标签序列 $\\mathbf{y}$ 的条件概率：</p><p>$$P(\\mathbf{y}|\\mathbf{x}) = \\frac{1}{Z(\\mathbf{x})} \\exp\\left(\\sum_{i,t} \\lambda_t f_t(y_{i-1}, y_i, \\mathbf{x}, i)\\right)$$</p><p>其中：</p><ul><li>$f_t$ 是特征函数，描述相邻标签之间的关系</li><li>$\\lambda_t$ 是特征函数的权重</li><li>$Z(\\mathbf{x})$ 是归一化因子（配分函数）</li></ul><h3 id="词袋模型的局限" tabindex="-1">词袋模型的局限 <a class="header-anchor" href="#词袋模型的局限" aria-label="Permalink to &quot;词袋模型的局限&quot;">​</a></h3><p>这一阶段常用的文本表示方法是<strong>词袋模型</strong>（Bag of Words），它通过统计词频来表示文本。但词袋模型有一个明显的局限——<strong>完全忽略了词语的顺序</strong>。</p><p><strong>示例</strong>：</p><table tabindex="0"><thead><tr><th>评论</th><th>分词结果</th></tr></thead><tbody><tr><td>&quot;服务很好但味道差劲&quot;</td><td>[&quot;服务&quot;, &quot;很&quot;, &quot;好&quot;, &quot;但&quot;, &quot;味道&quot;, &quot;差劲&quot;]</td></tr><tr><td>&quot;味道很好但服务差劲&quot;</td><td>[&quot;味道&quot;, &quot;很&quot;, &quot;好&quot;, &quot;但&quot;, &quot;服务&quot;, &quot;差劲&quot;]</td></tr></tbody></table><p>这两条评论在词袋模型中的特征向量是<strong>完全相同的</strong>，但它们表达的情感<strong>完全相反</strong>。</p><p>为了解决这个问题，引入了 <strong>N-gram 特征</strong>。使用 trigram（3-gram）后：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>评论A：[&quot;服务很好&quot;, &quot;很好但&quot;, &quot;好但味道&quot;, &quot;但味道差劲&quot;]</span></span>
<span class="line"><span>评论B：[&quot;味道很好&quot;, &quot;很好但&quot;, &quot;好但服务&quot;, &quot;但服务差劲&quot;]</span></span></code></pre></div><p>这样两条评论的特征向量就能区分开了。</p><hr><h2 id="第四阶段-深度学习时代-2010s" tabindex="-1">第四阶段：深度学习时代（2010s） <a class="header-anchor" href="#第四阶段-深度学习时代-2010s" aria-label="Permalink to &quot;第四阶段：深度学习时代（2010s）&quot;">​</a></h2><h3 id="时代背景-3" tabindex="-1">时代背景 <a class="header-anchor" href="#时代背景-3" aria-label="Permalink to &quot;时代背景&quot;">​</a></h3><p>自 2010 年代中期开始，深度学习在 NLP 中迅速崛起。基于神经网络的模型取代了传统手工特征工程，能够从海量数据中<strong>自动学习</strong>语义表示。</p><h3 id="核心模型" tabindex="-1">核心模型 <a class="header-anchor" href="#核心模型" aria-label="Permalink to &quot;核心模型&quot;">​</a></h3><h4 id="word2vec-2013" tabindex="-1">Word2Vec（2013） <a class="header-anchor" href="#word2vec-2013" aria-label="Permalink to &quot;Word2Vec（2013）&quot;">​</a></h4><p>Word2Vec 由 Google 的 Tomas Mikolov 团队提出，它通过神经网络为每个词生成一个<strong>稠密的、低维的向量表示</strong>，使得语义相近的词在向量空间中距离更近。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vec(&quot;国王&quot;) - vec(&quot;男人&quot;) + vec(&quot;女人&quot;) ≈ vec(&quot;女王&quot;)</span></span></code></pre></div><h4 id="rnn-lstm-gru" tabindex="-1">RNN / LSTM / GRU <a class="header-anchor" href="#rnn-lstm-gru" aria-label="Permalink to &quot;RNN / LSTM / GRU&quot;">​</a></h4><p>循环神经网络（RNN）及其变体 LSTM 和 GRU，是处理序列数据的经典模型。它们通过<strong>循环连接</strong>来建模序列中的上下文信息。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>时间步1: 输入&quot;我&quot; → 隐藏状态 h₁</span></span>
<span class="line"><span>时间步2: 输入&quot;爱&quot; → 隐藏状态 h₂ (结合 h₁)</span></span>
<span class="line"><span>时间步3: 输入&quot;NLP&quot; → 隐藏状态 h₃ (结合 h₂)</span></span></code></pre></div><h4 id="elmo-2018" tabindex="-1">ELMo（2018） <a class="header-anchor" href="#elmo-2018" aria-label="Permalink to &quot;ELMo（2018）&quot;">​</a></h4><p>ELMo（Embeddings from Language Models）是第一个成功应用于下游任务的<strong>上下文相关词向量</strong>模型。它基于双向 LSTM 语言模型，同一个词在不同上下文中会有不同的向量表示。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;苹果很好吃&quot; 中的 &quot;苹果&quot; → 向量 A（偏向水果含义）</span></span>
<span class="line"><span>&quot;苹果发布新手机&quot; 中的 &quot;苹果&quot; → 向量 B（偏向公司含义）</span></span></code></pre></div><h3 id="transformer-2017" tabindex="-1">Transformer（2017） <a class="header-anchor" href="#transformer-2017" aria-label="Permalink to &quot;Transformer（2017）&quot;">​</a></h3><p>2017 年，Google 团队发表了划时代的论文 <strong>&quot;Attention Is All You Need&quot;</strong>，提出了 <strong>Transformer</strong> 架构。它完全抛弃了循环结构，仅使用<strong>注意力机制</strong>来建模序列中的依赖关系。</p><p>Transformer 的优势：</p><ul><li><strong>并行计算</strong>：不像 RNN 需要逐步处理，可以同时处理整个序列</li><li><strong>长距离依赖</strong>：通过注意力机制直接建模任意两个位置之间的关系</li><li><strong>可扩展性</strong>：可以通过增加层数和参数量来提升性能</li></ul><p>我们将在后续章节中详细讲解 Transformer 的架构。</p><hr><h2 id="第五阶段-预训练模型时代-2018-2022" tabindex="-1">第五阶段：预训练模型时代（2018-2022） <a class="header-anchor" href="#第五阶段-预训练模型时代-2018-2022" aria-label="Permalink to &quot;第五阶段：预训练模型时代（2018-2022）&quot;">​</a></h2><h3 id="时代背景-4" tabindex="-1">时代背景 <a class="header-anchor" href="#时代背景-4" aria-label="Permalink to &quot;时代背景&quot;">​</a></h3><p>预训练模型的核心思想是：先在<strong>大规模无标注文本</strong>上进行预训练，学习通用的语言知识，然后在<strong>特定下游任务</strong>上进行微调（Fine-tuning）。</p><h3 id="核心模型-1" tabindex="-1">核心模型 <a class="header-anchor" href="#核心模型-1" aria-label="Permalink to &quot;核心模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>年份</th><th>架构</th><th>特点</th></tr></thead><tbody><tr><td>ELMo</td><td>2018</td><td>LSTM</td><td>上下文相关词向量</td></tr><tr><td>GPT</td><td>2018.6</td><td>Transformer Decoder</td><td>单向自回归语言模型</td></tr><tr><td>BERT</td><td>2018.10</td><td>Transformer Encoder</td><td>双向掩码语言模型</td></tr><tr><td>GPT-2</td><td>2019.2</td><td>Transformer Decoder</td><td>更大规模的生成模型</td></tr><tr><td>T5</td><td>2019.10</td><td>Transformer Encoder-Decoder</td><td>统一的文本到文本框架</td></tr><tr><td>GPT-3</td><td>2020.5</td><td>Transformer Decoder</td><td>1750 亿参数，少样本学习</td></tr></tbody></table><h3 id="bert-vs-gpt-两种范式" tabindex="-1">BERT vs GPT：两种范式 <a class="header-anchor" href="#bert-vs-gpt-两种范式" aria-label="Permalink to &quot;BERT vs GPT：两种范式&quot;">​</a></h3><p><strong>BERT（双向编码器）</strong>：</p><ul><li>使用 Transformer 的<strong>编码器</strong>部分</li><li>通过<strong>掩码语言模型</strong>（MLM）进行预训练：随机遮盖一些词，让模型预测被遮盖的词</li><li>适合<strong>理解型</strong>任务（分类、问答、NER）</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入：我 爱 [MASK] 语言 处理</span></span>
<span class="line"><span>输出：我 爱 自然 语言 处理</span></span></code></pre></div><p><strong>GPT（单向解码器）</strong>：</p><ul><li>使用 Transformer 的<strong>解码器</strong>部分</li><li>通过<strong>自回归语言模型</strong>进行预训练：根据前面的词预测下一个词</li><li>适合<strong>生成型</strong>任务（文本生成、对话）</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入：我 爱 自然</span></span>
<span class="line"><span>输出：我 爱 自然 语言</span></span></code></pre></div><hr><h2 id="第六阶段-大语言模型时代-2022-至今" tabindex="-1">第六阶段：大语言模型时代（2022-至今） <a class="header-anchor" href="#第六阶段-大语言模型时代-2022-至今" aria-label="Permalink to &quot;第六阶段：大语言模型时代（2022-至今）&quot;">​</a></h2><h3 id="时代背景-5" tabindex="-1">时代背景 <a class="header-anchor" href="#时代背景-5" aria-label="Permalink to &quot;时代背景&quot;">​</a></h3><p>2022 年底，ChatGPT 的发布标志着 NLP 进入了<strong>大语言模型</strong>（Large Language Model，LLM）时代。这些模型通过<strong>海量数据</strong>和<strong>超大规模参数</strong>，展现出了前所未有的语言理解和生成能力。</p><h3 id="核心模型-2" tabindex="-1">核心模型 <a class="header-anchor" href="#核心模型-2" aria-label="Permalink to &quot;核心模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>年份</th><th>参数量</th><th>特点</th></tr></thead><tbody><tr><td>ChatGPT</td><td>2022.11</td><td>~1750 亿</td><td>基于 GPT-3.5，RLHF 对齐</td></tr><tr><td>GPT-4</td><td>2023.3</td><td>未公开</td><td>多模态能力</td></tr><tr><td>LLaMA</td><td>2023.2</td><td>7B-65B</td><td>Meta 开源模型</td></tr><tr><td>LLaMA 2</td><td>2023.7</td><td>7B-70B</td><td>改进的开源模型</td></tr><tr><td>DeepSeek</td><td>2024</td><td>67B</td><td>中国开源模型</td></tr><tr><td>GPT-4o</td><td>2024.5</td><td>未公开</td><td>多模态、更快推理</td></tr></tbody></table><h3 id="关键技术突破" tabindex="-1">关键技术突破 <a class="header-anchor" href="#关键技术突破" aria-label="Permalink to &quot;关键技术突破&quot;">​</a></h3><ol><li><strong>规模定律（Scaling Law）</strong>：模型性能随参数量、数据量和计算量的增加而持续提升</li><li><strong>上下文学习（In-Context Learning）</strong>：无需微调，仅通过提示就能完成新任务</li><li><strong>思维链（Chain of Thought）</strong>：通过逐步推理来解决复杂问题</li><li><strong>RLHF（人类反馈强化学习）</strong>：让模型的输出更好地对齐人类偏好</li></ol><hr><h2 id="技术演进总览" tabindex="-1">技术演进总览 <a class="header-anchor" href="#技术演进总览" aria-label="Permalink to &quot;技术演进总览&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1950s  规则系统 ──────────────────┐</span></span>
<span class="line"><span>       Georgetown-IBM, ELIZA      │</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>1990s  统计方法 ──────────────────┤</span></span>
<span class="line"><span>       N-gram, HMM, 最大熵        │</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>2000s  机器学习 ──────────────────┤</span></span>
<span class="line"><span>       SVM, CRF, 逻辑回归          │</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>2013   Word2Vec ──────────────────┤</span></span>
<span class="line"><span>       静态词向量                   │</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>2017   Transformer ───────────────┤</span></span>
<span class="line"><span>       注意力机制                   │</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>2018   预训练模型 ─────────────────┤</span></span>
<span class="line"><span>       ELMo → GPT → BERT           │</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>2022   大语言模型 ─────────────────┘</span></span>
<span class="line"><span>       ChatGPT → GPT-4 → LLaMA</span></span></code></pre></div><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>本章回顾了 NLP 从 1950 年代到今天的发展历程。每一代技术的出现都是为了解决前一代技术的局限：</p><ul><li><strong>规则系统</strong> → 无法扩展 → <strong>统计方法</strong></li><li><strong>统计方法</strong> → 特征工程复杂 → <strong>深度学习</strong></li><li><strong>深度学习</strong> → 需要大量标注数据 → <strong>预训练模型</strong></li><li><strong>预训练模型</strong> → 任务特定微调 → <strong>大语言模型</strong></li></ul><p>理解这段演进历史，有助于我们理解为什么 Transformer、BERT、GPT 等架构被设计成现在这个样子。在后续章节中，我们将逐一深入讲解这些技术的原理和实现。</p>`,118)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
